  { id: 'A.8.11', norm: 'ISO 27001', name: 'Enmascaramiento de datos (Anonimización)', state: 'No iniciado', ley: 'Ley 19.628',
    description: 'Verificar el uso de técnicas de anonimización/seudonimización en ambientes no productivos. Revisar herramientas de enmascaramiento, alcance de datos protegidos y validación de irreversibilidad.' },
  { id: 'A.8.12', norm: 'ISO 27001', name: 'Prevención de fuga de datos (DLP)', state: 'No iniciado', ley: 'Ley 21.459 / Salud / CMF',
    description: 'Evaluar la solución DLP implementada: reglas configuradas, canales monitoreados (correo, web, USB), alertas generadas, incidentes de fuga detectados y acciones de remediación ejecutadas.' },
  { id: 'A.8.13', norm: 'ISO 27001', name: 'Respaldo de información (Backups)', state: 'No iniciado', ley: 'Normativa Tributaria / Salud',
    description: 'Revisar la política de respaldo: frecuencia, retención, cifrado de backups, almacenamiento offsite/nube. Verificar pruebas de restauración periódicas, RPO/RTO cumplidos y monitoreo de éxito de backups.' },
  { id: 'A.8.14', norm: 'ISO 27001', name: 'Redundancia de instalaciones de procesamiento', state: 'No iniciado', ley: 'CMF / Continuidad',
    description: 'Verificar la redundancia de infraestructura crítica: servidores en alta disponibilidad, failover automático, sitio de recuperación activo/pasivo y pruebas de conmutación realizadas.' },
  { id: 'A.8.15', norm: 'ISO 27001', name: 'Generación de registros (Logging)', state: 'No iniciado', ley: 'Ley 21.459',
    description: 'Evaluar la política de logging: sistemas y eventos registrados, formato estándar, centralización (SIEM), retención de logs, protección contra alteración y revisión periódica de registros.' },
  { id: 'A.8.16', norm: 'ISO 27001', name: 'Actividades de seguimiento (Monitoreo activo)', state: 'No iniciado', ley: 'Ley 21.459',
    description: 'Revisar las capacidades de monitoreo activo: herramientas SIEM/SOC, reglas de correlación, alertas configuradas, tiempos de detección (MTTD), personal de monitoreo y cobertura 24/7.' },
  { id: 'A.8.17', norm: 'ISO 27001', name: 'Sincronización de relojes', state: 'No iniciado', ley: 'Ley 21.459 (Evidencia Forense)',
    description: 'Verificar que todos los sistemas están sincronizados con una fuente de tiempo confiable (NTP). Revisar la configuración de servidores NTP, zona horaria consistente y monitoreo de desviaciones.' },
  { id: 'A.8.18', norm: 'ISO 27001', name: 'Uso de programas de utilidad privilegiada', state: 'No iniciado', ley: 'Normativa General',
    description: 'Evaluar el control sobre herramientas de utilidad privilegiada: inventario de herramientas autorizadas, restricción de uso, logging de ejecución y procedimiento de aprobación para uso excepcional.' },
  { id: 'A.8.19', norm: 'ISO 27001', name: 'Instalación de software en sistemas operativos', state: 'No iniciado', ley: 'Normativa General',
    description: 'Revisar la política de instalación de software: lista blanca de software aprobado, restricción de permisos de instalación, proceso de solicitud y aprobación, y auditoría de software instalado.' },
  { id: 'A.8.20', norm: 'ISO 27001', name: 'Seguridad en redes', state: 'No iniciado', ley: 'Normativa General',
    description: 'Evaluar los controles de seguridad de red: firewalls, IDS/IPS, políticas de acceso, segmentación de red, monitoreo de tráfico, gestión de reglas y revisiones periódicas de arquitectura de red.' },
  { id: 'A.8.21', norm: 'ISO 27001', name: 'Seguridad de los servicios de red', state: 'No iniciado', ley: 'Normativa General',
    description: 'Verificar la seguridad de los servicios de red (DNS, DHCP, proxy): configuración hardening, SLAs con ISPs, controles de disponibilidad y monitoreo de servicios críticos de red.' },
  { id: 'A.8.22', norm: 'ISO 27001', name: 'Segregación en redes', state: 'No iniciado', ley: 'PCI-DSS / Salud',
    description: 'Revisar la segmentación de red implementada: VLANs, zonas DMZ, microsegmentación. Verificar diagramas de red actualizados, reglas de comunicación entre segmentos y pruebas de aislamiento.' },
  { id: 'A.8.23', norm: 'ISO 27001', name: 'Filtrado web', state: 'No iniciado', ley: 'Normativa General',
    description: 'Evaluar la solución de filtrado web: categorías bloqueadas, listas blancas/negras, política de uso, excepciones documentadas, reportes de navegación y protección contra sitios maliciosos.' },
  { id: 'A.8.24', norm: 'ISO 27001', name: 'Uso de criptografía y gestión de claves', state: 'No iniciado', ley: 'Ley 19.628 / Salud / CMF',
    description: 'Revisar la política criptográfica: algoritmos aprobados, gestión del ciclo de vida de claves (generación, distribución, rotación, revocación), uso de HSM y certificados digitales vigentes.' },
  { id: 'A.8.25', norm: 'ISO 27001', name: 'Ciclo de vida del desarrollo seguro (SDLC)', state: 'No iniciado', ley: 'Normativa General',
    description: 'Evaluar la integración de seguridad en el SDLC: requisitos de seguridad, modelado de amenazas, revisión de código seguro, pruebas de seguridad (SAST/DAST) y aprobación de seguridad pre-producción.' },
  { id: 'A.8.26', norm: 'ISO 27001', name: 'Requisitos de seguridad en la aplicación', state: 'No iniciado', ley: 'Normativa General',
    description: 'Verificar que las aplicaciones incluyen requisitos de SI desde el diseño: validación de entrada/salida, manejo de sesiones, autenticación, autorización y cumplimiento de estándares (OWASP Top 10).' },
  { id: 'A.8.27', norm: 'ISO 27001', name: 'Principios de arquitectura e ingeniería de sistemas seguros', state: 'No iniciado', ley: 'Normativa General',
    description: 'Revisar los principios de diseño seguro aplicados: defensa en profundidad, mínimo privilegio, fail-safe, arquitecturas de referencia de seguridad y revisiones de arquitectura documentadas.' },
  { id: 'A.8.28', norm: 'ISO 27001', name: 'Codificación segura', state: 'No iniciado', ley: 'OWASP / Normativa General',
    description: 'Evaluar las prácticas de codificación segura: estándar de desarrollo seguro adoptado, capacitación a desarrolladores, uso de herramientas SAST/DAST, revisión de código y gestión de dependencias.' },
  { id: 'A.8.29', norm: 'ISO 27001', name: 'Pruebas de seguridad en el desarrollo y la aceptación', state: 'No iniciado', ley: 'Normativa General',
    description: 'Verificar la ejecución de pruebas de seguridad en la aceptación de sistemas: pentesting pre-producción, escaneo de vulnerabilidades, pruebas de regresión de seguridad e informes con hallazgos.' },
  { id: 'A.8.30', norm: 'ISO 27001', name: 'Desarrollo externalizado', state: 'No iniciado', ley: 'Normativa General',
    description: 'Revisar los controles sobre desarrollo tercerizado: requisitos de seguridad en contratos, revisiones de código entregado, propiedad del código, pruebas de seguridad y auditoría del proveedor.' },
  { id: 'A.8.31', norm: 'ISO 27001', name: 'Separación de entornos de desarrollo, prueba y producción', state: 'No iniciado', ley: 'Normativa General',
    description: 'Verificar la separación efectiva de entornos (dev/test/prod): accesos diferenciados, datos de producción no usados en pruebas sin anonimizar, procedimiento de promoción entre entornos.' },
  { id: 'A.8.32', norm: 'ISO 27001', name: 'Gestión del cambio', state: 'No iniciado', ley: 'Normativa General',
    description: 'Evaluar el proceso de gestión de cambios: registro de solicitudes, análisis de impacto, aprobación formal, ventanas de mantenimiento, rollback planificado y revisión post-implementación.' },
  { id: 'A.8.33', norm: 'ISO 27001', name: 'Información de pruebas', state: 'No iniciado', ley: 'Ley 19.628',
    description: 'Verificar que datos de pruebas no contienen información personal o sensible real. Revisar proceso de generación de datos sintéticos, controles de acceso al entorno de pruebas y destrucción post-uso.' },
  { id: 'A.8.34', norm: 'ISO 27001', name: 'Protección de los sistemas de información durante la auditoría', state: 'No iniciado', ley: 'Normativa General',
    description: 'Revisar los controles para proteger sistemas durante auditorías: accesos limitados y monitoreados para auditores, uso de cuentas temporales, restricción de herramientas y supervisión de actividades.' }
